// 2. Fungsi untuk menyensor teks, memperbaiki enter, dan melindungi URL
function censorText(text) {
  if (typeof text !== 'string') return text;

  // Langkah A: Ekstrak dan Lindungi URL
  const urlRegex = /(https?:\/\/[^\s"'<>]+)/g;
  const extractedUrls = [];

  let protectedText = text.replace(urlRegex, (match) => {
    extractedUrls.push(match);
    return `__URL_PLACEHOLDER_${extractedUrls.length - 1}__`; 
  });

  // Langkah B: Perbaiki Newline
  let result = protectedText.replace(/\\n/g, '\n').replace(/\/n/g, '\n');

  // Langkah C: Terapkan Sensor Kata dari Dictionary dengan Case Matching yang Akurat
  for (const [word, replacement] of Object.entries(dictionary)) {
    const regex = new RegExp(word, 'gi');

    result = result.replace(regex, (match) => {
      const firstCharMatched = match.charAt(0);
      const firstCharRep = replacement.charAt(0);
      const restRep = replacement.slice(1);

      // Cek apakah karakter pertama pengganti adalah huruf (punya versi besar/kecil)
      const hasCase = firstCharRep.toLowerCase() !== firstCharRep.toUpperCase();

      if (hasCase) {
        // Jika huruf pertama teks asli adalah KAPITAL
        if (firstCharMatched === firstCharMatched.toUpperCase()) {
          return firstCharRep.toUpperCase() + restRep;
        } 
        // Jika huruf pertama teks asli adalah KECIL
        else {
          return firstCharRep.toLowerCase() + restRep;
        }
      }

      // Jika karakter pertama pengganti adalah angka/simbol (misal: '1' pada 1srαǝl), biarkan aslinya
      return replacement;
    });
  }

  // Langkah D: Kembalikan URL asli
  result = result.replace(/__URL_PLACEHOLDER_(\d+)__/g, (match, index) => {
    return extractedUrls[parseInt(index)];
  });

  return result;
}

// 3. Fungsi rekursif untuk memproses struktur data (Object, Array, String)
function processItem(item) {
  if (typeof item === 'string') {
    if ((item.trim().startsWith('{') && item.trim().endsWith('}')) || 
        (item.trim().startsWith('[') && item.trim().endsWith(']'))) {
      try {
        const parsed = JSON.parse(item);
        const processed = processItem(parsed);
        return JSON.stringify(processed);
      } catch (e) {
        return censorText(item);
      }
    }
    return censorText(item);

  } else if (Array.isArray(item)) {
    return item.map(processItem);

  } else if (item !== null && typeof item === 'object') {
    const result = {};
    for (const [key, value] of Object.entries(item)) {
      result[key] = processItem(value);
    }
    return result;
  }

  return item; 
}

